const fs = global.get('fs');
const { execSync } = global.get('child_process');
const iniPath = '/home/pi/fleet-management/inventory.ini';
let raw;
try { raw = fs.readFileSync(iniPath, 'utf8'); } catch(e) { node.error(e); msg.payload = 'Error reading inventory'; return msg; }
const lines = raw.split('\n');
const groups = {};
let currentGroup = null;
for (let line of lines) {
    line = line.trim();
    if (!line || line.startsWith('#')) continue;
    const groupMatch = line.match(/^\[([^\]:]+)\]$/);
    if (groupMatch) { currentGroup = groupMatch[1]; if (!groups[currentGroup]) groups[currentGroup] = []; continue; }
    if (currentGroup && line.includes('ansible_host')) {
        const parts = line.split(/\s+/);
        const name = parts[0];
        const vars = {};
        parts.slice(1).forEach(p => { const [k, v] = p.split('='); if (k && v) vars[k] = v; });
        groups[currentGroup].push({ name, ...vars });
    }
}
msg.inventory = JSON.stringify(groups);
msg.groupDescriptions = JSON.stringify(flow.get('groupDescriptions') || {});

// Collect non-internal IPv4 addresses using ip command
const ips = [];
try {
    const ipOut = execSync('ip -4 addr show', { timeout: 5000 }).toString();
    let currentIface = null;
    ipOut.split('\n').forEach(function(line) {
        const ifaceMatch = line.match(/^\d+:\s+(\S+):/);
        if (ifaceMatch) { currentIface = ifaceMatch[1]; return; }
        const addrMatch = line.match(/inet\s+(\d+\.\d+\.\d+\.\d+)\/\d+/);
        if (addrMatch && currentIface && currentIface !== 'lo') {
            ips.push({ iface: currentIface, address: addrMatch[1] });
        }
    });
} catch(e) { node.warn('Could not get network interfaces: ' + e.message); }
msg.controlPiIPs = JSON.stringify(ips);
return msg;

