const fs = global.get('fs');
const cacheDir = '/var/cache/apt-cacher-ng';
const pkgFile = '/home/pi/fleet-management/vars/packages.yml';
let userPackages = [];

try {
    const raw = fs.readFileSync(pkgFile, 'utf8');
