            const m = line.match(/^\s+-\s+(.+)$/);
            if (m) userPackages.push(m[1].trim());
        }
    });
} catch(e) {
    node.warn('Could not read packages.yml: ' + e.message);
}

// Find matching .deb files in cache for each tracked package
const packages = [];
const walk = function(dir) {
    try {
        const entries = fs.readdirSync(dir, { withFileTypes: true });
        for (const e of entries) {
            if (e.isDirectory()) walk(dir + '/' + e.name);
            else if (e.name.endsWith('.deb')) {
                const parts = e.name.replace('.deb','').split('_');
                const pkgName = parts[0];
                if (userPackages.includes(pkgName)) {
                    const stat = fs.statSync(dir + '/' + e.name);
                    packages.push({ file: dir+'/'+e.name, name: pkgName, version: parts[1]||'', size: stat.size });
                }
            }
        }
    } catch(e) {}
};
walk(cacheDir);
packages.sort(function(a,b){ return a.name.localeCompare(b.name); });

// Include packages tracked in yml but not yet found in cache (show with no file)
const foundNames = packages.map(function(p){ return p.name; });
userPackages.forEach(function(name) {
    if (!foundNames.includes(name)) {
        packages.push({ file: '', name: name, version: '—', size: 0 });
    }
});

msg.payload = { ok: true, packages };
return msg;

const fs = global.get('fs');
