    // Add to apt_packages section in packages.yml
    let lines = [];
    try { lines = fs.readFileSync(pkgFile, 'utf8').split('\n'); } catch(e) {}
    const already = lines.some(function(l) { const m=l.match(/^\s+-\s+(.+)$/); return m && m[1].trim()===name; });
    if (!already) {
        const sectionIdx = lines.findIndex(function(l){ return l.trim() === 'apt_packages:'; });
        if (sectionIdx >= 0) {
            lines.splice(sectionIdx + 1, 0, ' - ' + name);
        } else {
            if (lines.length && lines[lines.length-1] !== '') lines.push('');
            lines.push('apt_packages:');
            lines.push(' - ' + name);
        }
        fs.writeFileSync(pkgFile, lines.join('\n'));
    }

    msg.payload = { ok: true };
} catch(e) {
    msg.payload = { ok: false, error: e.stderr ? e.stderr.toString() : e.message };
}
return msg;

