const { execSync } = global.get('child_process');

try {
    const raw = execSync(
        `ANSIBLE_CONFIG=/home/pi/fleet-management/ansible.cfg ansible fleet -i /home/pi/fleet-management/inventory.ini -m setup -a "filter=ansible_hostname,ansible_default_ipv4,ansible_distribution,ansible_distribution_version" 2>&1`,
        { timeout: 120000 }
    ).toString();

    const aptRaw = execSync(
        `ANSIBLE_CONFIG=/home/pi/fleet-management/ansible.cfg ansible fleet -i /home/pi/fleet-management/inventory.ini -m shell -a "cat /etc/apt/apt.conf.d/01proxy 2>/dev/null || echo MISSING" 2>&1`,
        { timeout: 60000 }
    ).toString();

    const npmRaw = execSync(
        `ANSIBLE_CONFIG=/home/pi/fleet-management/ansible.cfg ansible fleet -i /home/pi/fleet-management/inventory.ini -m shell -a "npm config get registry 2>/dev/null || echo MISSING" 2>&1`,
        { timeout: 60000 }
    ).toString();

    node.warn('APT RAW FULL: ' + JSON.stringify(aptRaw));
    node.warn('NPM RAW FULL: ' + JSON.stringify(npmRaw));

    const results = {};

    // Multi-line setup output: collect JSON block per host using brace-depth tracking
    const lines = raw.split('\n');
    let currentHost = null;
    let jsonBuffer = [];
    let collecting = false;
    let braceDepth = 0;

    lines.forEach(function(line) {
        const hostMatch = line.match(/^(\S+)\s*\|\s*SUCCESS\s*=>\s*(\{.*)$/);
        if (hostMatch) {
            currentHost = hostMatch[1];
            const partial = hostMatch[2];
            jsonBuffer = [partial];
            braceDepth = (partial.match(/\{/g)||[]).length - (partial.match(/\}/g)||[]).length;
            if (braceDepth <= 0) {
                try {
                    const facts = JSON.parse(partial);
                    const af = facts.ansible_facts || {};
                    if (!results[currentHost]) results[currentHost] = {};
                    results[currentHost].hostname = af.ansible_hostname || '—';
                    results[currentHost].mac = (af.ansible_default_ipv4 || {}).macaddress || '—';
                    results[currentHost].os = af.ansible_distribution && af.ansible_distribution_version
                        ? af.ansible_distribution + ' ' + af.ansible_distribution_version : '—';
                } catch(e) {}
                collecting = false;
            } else {
                collecting = true;
            }
            return;
        }
        if (collecting && currentHost) {
            jsonBuffer.push(line);
            braceDepth += (line.match(/\{/g)||[]).length - (line.match(/\}/g)||[]).length;
            if (braceDepth <= 0) {
                collecting = false;
                try {
                    const facts = JSON.parse(jsonBuffer.join('\n'));
                    const af = facts.ansible_facts || {};
                    if (!results[currentHost]) results[currentHost] = {};
                    results[currentHost].hostname = af.ansible_hostname || '—';
                    results[currentHost].mac = (af.ansible_default_ipv4 || {}).macaddress || '—';
                    results[currentHost].os = af.ansible_distribution && af.ansible_distribution_version
                        ? af.ansible_distribution + ' ' + af.ansible_distribution_version : '—';
                } catch(e) {
                    node.warn('Facts parse error for ' + currentHost + ': ' + e.message);
                }
                currentHost = null;
                jsonBuffer = [];
            }
        }
    });

    // APT proxy
    const aptLines = aptRaw.split('\n');
    aptLines.forEach(function(line, i) {
        const hostMatch = line.match(/^(\S+)\s*\|\s*(?:CHANGED|SUCCESS).*>>$/);
        if (!hostMatch) return;
        const host = hostMatch[1];
        const output = (aptLines[i+1]||'').trim();
        if (!results[host]) results[host] = {};
        results[host].apt_proxy = output === 'MISSING' || output === '' ? false : true;
    });

    // NPM registry
    const npmLines = npmRaw.split('\n');
    npmLines.forEach(function(line, i) {
        const hostMatch = line.match(/^(\S+)\s*\|\s*(?:CHANGED|SUCCESS).*>>$/);
        if (!hostMatch) return;
        const host = hostMatch[1];
        const output = (npmLines[i+1]||'').trim();
        if (!results[host]) results[host] = {};
        results[host].npm_registry = output.includes('4873') ? true : false;
    });

    msg.payload = { ok: true, facts: results };
} catch(e) {
    msg.payload = { ok: false, error: e.message };
}
return msg;

